#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypePeatAdapter: FfiConverter {
    typealias FfiType = UInt64
    typealias SwiftType = PeatAdapter

    public static func lift(_ handle: UInt64) throws -> PeatAdapter {
        return PeatAdapter(unsafeFromHandle: handle)
    }

    public static func lower(_ value: PeatAdapter) -> UInt64 {
        return value.uniffiCloneHandle()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> PeatAdapter {
        let handle: UInt64 = try readInt(&buf)
        return try lift(handle)
    }

    public static func write(_ value: PeatAdapter, into buf: inout [UInt8]) {
        writeInt(&buf, lower(value))
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypePeatAdapter_lift(_ handle: UInt64) throws -> PeatAdapter {
    return try FfiConverterTypePeatAdapter.lift(handle)
}

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypePeatAdapter_lower(_ value: PeatAdapter) -> UInt64 {
    return FfiConverterTypePeatAdapter.lower(value)
}






/**
 * Main PeatMesh wrapper for UniFFI
 */
public protocol PeatMeshWrapperProtocol: AnyObject, Sendable {
    
    /**
     * Record our ACK for the current emergency
     * Returns the document bytes to broadcast, or None if no emergency is active
     */
    func ackEmergency(timestamp: UInt64)  -> Data?
    
    /**
     * Add an event observer
     */
    func addObserver(callback: MeshEventCallback) 
    
    /**
     * Check if all peers have ACKed the current emergency
     */
    func allPeersAcked()  -> Bool
    
    /**
     * Wrap an app-layer payload (e.g. the peat-ffi BLE envelope, 0xAF-marked)
     * for transmission over BLE and return the bytes to write to the radio.
     * In unencrypted mode this is a passthrough; with mesh encryption enabled
     * it returns the ciphertext. Mirrors Android `PeatBtle.broadcastBytes`.
     * The platform layer transmits the returned bytes to all connected peers;
     * the peer side surfaces the original payload as `DataReceivedResult.relay_data`.
     */
    func broadcastBytes(payload: Data)  -> Data
    
    /**
     * Build current document for sync
     */
    func buildDocument()  -> Data
    
    /**
     * Clear the current emergency event
     */
    func clearEmergency() 
    
    /**
     * Clear the current event
     */
    func clearEvent() 
    
    /**
     * Get connected peer count
     */
    func connectedCount()  -> UInt32
    
    /**
     * Get device name for BLE advertising
     */
    func deviceName()  -> String
    
    /**
     * Get connected peers only
     */
    func getConnectedPeers()  -> [MeshPeer]
    
    /**
     * Get emergency status info
     * Returns (source_node, timestamp, acked_count, pending_count) if emergency is active
     */
    func getEmergencyStatus()  -> EmergencyStatus?
    
    /**
     * Get all known peers
     */
    func getPeers()  -> [MeshPeer]
    
    /**
     * Check if there's an active document-based emergency
     */
    func hasActiveEmergency()  -> Bool
    
    /**
     * Check if a specific peer has ACKed the current emergency
     */
    func hasPeerAcked(peerId: UInt32)  -> Bool
    
    /**
     * Check if ACK is currently active
     */
    func isAckActive()  -> Bool
    
    /**
     * Check if emergency is currently active
     */
    func isEmergencyActive()  -> Bool
    
    /**
     * Check if a device matches our mesh
     */
    func matchesMesh(deviceMeshId: String?)  -> Bool
    
    /**
     * Get mesh ID
     */
    func meshId()  -> String
    
    /**
     * Get local node ID
     */
    func nodeId()  -> UInt32
    
    /**
     * Called when a BLE connection is established
     */
    func onBleConnected(identifier: String, nowMs: UInt64)  -> UInt32?
    
    /**
     * Called when BLE data is received without a known identifier
     *
     * Use this when receiving data from a peripheral (acting as Central)
     * where the identifier doesn't map to a known peer. This method extracts
     * the source node ID from the document itself.
     */
    func onBleData(identifier: String, data: Data, nowMs: UInt64)  -> DataReceivedResult?
    
    /**
     * Called when BLE data is received from a peer
     * Returns merge result if successful
     */
    func onBleDataReceived(identifier: String, data: Data, nowMs: UInt64)  -> DataReceivedResult?
    
    /**
     * Receive BLE data on the ANONYMOUS path — the one that recognizes the
     * 0xAF app-layer marker and returns it as `relay_data` (the opaque relay
     * the Android `PeatBtle` uses: `onBleDataReceivedAnonymous`). The bare
     * `on_ble_data` / `on_ble_data_received` paths fall through to
     * `merge_document` and DROP 0xAF frames, so the bridge MUST use this one
     * for the opaque relay to surface inbound app frames.
     */
    func onBleDataReceivedAnonymous(identifier: String, data: Data, nowMs: UInt64)  -> DataReceivedResult?
    
    /**
     * Called when a BLE connection is lost
     */
    func onBleDisconnected(identifier: String, reason: MeshDisconnectReason)  -> UInt32?
    
    /**
     * Called when a BLE device is discovered
     * Returns the peer if it's a valid Peat peer, None otherwise
     */
    func onBleDiscovered(identifier: String, name: String?, rssi: Int8, meshId: String?, nowMs: UInt64)  -> MeshPeer?
    
    /**
     * Called when a remote device connects to us (incoming connection)
     */
    func onIncomingConnection(identifier: String, nodeId: UInt32, nowMs: UInt64)  -> Bool
    
    /**
     * Get peer count
     */
    func peerCount()  -> UInt32
    
    /**
     * Send an ACK event (legacy - uses peripheral event only)
     * Returns the document bytes to broadcast via BLE
     */
    func sendAck(timestamp: UInt64)  -> Data
    
    /**
     * Send an emergency event (legacy - uses peripheral event only)
     * Returns the document bytes to broadcast via BLE
     */
    func sendEmergency(timestamp: UInt64)  -> Data
    
    /**
     * Start a new emergency event with ACK tracking for specified peers
     * Returns the document bytes to broadcast via BLE
     */
    func startEmergency(timestamp: UInt64, knownPeers: [UInt32])  -> Data
    
    /**
     * Start a new emergency event with ACK tracking for all known peers
     * Returns the document bytes to broadcast via BLE
     */
    func startEmergencyWithKnownPeers(timestamp: UInt64)  -> Data
    
    /**
     * Call periodically to perform maintenance tasks
     * Returns document bytes if a sync broadcast is needed
     */
    func tick(nowMs: UInt64)  -> Data?
    
    /**
     * Get total counter value
     */
    func totalCount()  -> UInt64
    
}
