/**
 * Result of receiving BLE data
 */
public struct DataReceivedResult: Equatable, Hashable {
    /**
     * Node ID of sender
     */
    public var sourceNode: UInt32
    /**
     * Whether document contained an emergency event
     */
    public var isEmergency: Bool
    /**
     * Whether document contained an ACK event
     */
    public var isAck: Bool
    /**
     * Whether counter changed (new data)
     */
    public var counterChanged: Bool
    /**
     * Whether emergency state changed (new emergency or ACK updates)
     */
    public var emergencyChanged: Bool
    /**
     * Total counter value after merge
     */
    public var totalCount: UInt64
    /**
     * Event timestamp (0 if no event) - use to detect duplicate events
     */
    public var eventTimestamp: UInt64
    /**
     * App-layer relay payload (0xAF-marked) passed through opaquely by
     * peat-btle. Carries the peat-ffi BLE envelope when the bridge runs
     * peat-btle as an opaque relay (mirrors Android `result.relayData`).
     * `None` when the frame was an internal peat-btle document.
     */
    public var relayData: Data?

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(
        /**
         * Node ID of sender
         */sourceNode: UInt32, 
        /**
         * Whether document contained an emergency event
         */isEmergency: Bool, 
        /**
         * Whether document contained an ACK event
         */isAck: Bool, 
        /**
         * Whether counter changed (new data)
         */counterChanged: Bool, 
        /**
         * Whether emergency state changed (new emergency or ACK updates)
         */emergencyChanged: Bool, 
        /**
         * Total counter value after merge
         */totalCount: UInt64, 
        /**
         * Event timestamp (0 if no event) - use to detect duplicate events
         */eventTimestamp: UInt64, 
        /**
         * App-layer relay payload (0xAF-marked) passed through opaquely by
         * peat-btle. Carries the peat-ffi BLE envelope when the bridge runs
         * peat-btle as an opaque relay (mirrors Android `result.relayData`).
         * `None` when the frame was an internal peat-btle document.
         */relayData: Data?) {
        self.sourceNode = sourceNode
        self.isEmergency = isEmergency
        self.isAck = isAck
        self.counterChanged = counterChanged
        self.emergencyChanged = emergencyChanged
        self.totalCount = totalCount
        self.eventTimestamp = eventTimestamp
        self.relayData = relayData
    }

    

    
}

